from typing import Callable, Any, TypeVar, Optional

R = TypeVar('R')

def retry(func: Callable[[], R], times: int = 3, delay: Optional[int] = 0, exceptions: Optional[tuple] = (Exception,)) -> R:
    """
    Retry a function call a specified number of times with optional delay.

    Args:
        func (Callable[[], R]): The function to be executed.
        times (int): Number of times to retry the function call.
        delay (Optional[int]): Delay between retries in seconds.
        exceptions (Optional[tuple]): A tuple of exception types to catch and retry on.

    Returns:
        R: The result of the function call if successful.

    Raises:
        Exception: Propagates the last exception if all retries fail.
    """
    @wraps(func)
    def wrapper() -> R:
        for attempt in range(times):
            try:
                return func()
            except exceptions as e:
                logging.warning(f"Attempt {attempt + 1} failed with exception: {e}")
                if attempt < times - 1:
                    time.sleep(delay)
                else:
                    logging.error("All attempts failed.")
                    raise
    return wrapper()

# Example usage
if __name__ == "__main__":
    logging.basicConfig(level=logging.INFO)

    @retry(times=5, delay=2)
    def unreliable_function():
        # Simulating a function that may fail
        import random
        if random.random() < 0.7:
            raise ValueError("Simulated failure")
        return "Success!"

    try:
        result = unreliable_function()
        print(result)
    except Exception as e:
        print(f"Function failed after retries: {e}")
