import time
import logging
from functools import wraps
from typing import Callable, Type, Tuple, Any, Optional

logger = logging.getLogger(__name__)


def retry(
    func: Optional[Callable] = None,
    *,
    times: int = 3,
    delay: float = 0,
    exceptions: Tuple[Type[BaseException], ...] = (Exception,),
) -> Callable:
    """
    A decorator that retries a function call if specified exceptions occur.

    Args:
        func: The function to be decorated. This parameter is optional to allow use as a decorator.
        times: The maximum number of attempts. Defaults to 3.
        delay: The delay in seconds between attempts. Defaults to 0 (no delay).
        exceptions: A tuple of exception classes that trigger a retry. Defaults to (Exception,).

    Raises:
        The last encountered exception if all attempts fail.

    Returns:
        A wrapped function with retry logic.

    Example:

        @retry(times=5, delay=1, exceptions=(ValueError,))
        def risky_operation():
            ...
    """
    if func is None:
        # Allows usage of the decorator with parameters.
        return lambda f: retry(f, times=times, delay=delay, exceptions=exceptions)

    @wraps(func)
    def wrapper(*args: Any, **kwargs: Any) -> Any:
        last_exception: Optional[BaseException] = None
        for attempt in range(1, times + 1):
            try:
                return func(*args, **kwargs)
            except exceptions as error:
                last_exception = error
                if attempt < times:
                    logger.warning(
                        "Attempt %d of %d failed for function '%s' with error: %s. Retrying in %.2f seconds...",
                        attempt,
                        times,
                        func.__name__,
                        error,
                        delay,
                    )
                    if delay:
                        time.sleep(delay)
                else:
                    logger.error(
                        "All %d attempts failed for function '%s'. Raising last encountered exception: %s",
                        times,
                        func.__name__,
                        error,
                    )
                    raise
        # In case no exception was thrown but somehow the loop ends
        raise last_exception  # type: ignore

    return wrapper


# Example usage:
if __name__ == "__main__":
    # Configure logging to display messages to the console.
    logging.basicConfig(level=logging.INFO)

    @retry(times=3, delay=2, exceptions=(ValueError,))
    def unstable_function():
        from random import randint
        num = randint(0, 10)
        if num < 8:
            raise ValueError(f"Random number {num} is too low!")
        return num

    try:
        result = unstable_function()
        print("Function succeeded with result:", result)
    except Exception as e:
        print("Function failed after retries:", e)

