import functools
import logging
import random
import time
from typing import Any, Callable, Optional, Tuple, Type, Union

logger = logging.getLogger(__name__)


class RetryError(Exception):
    """Raised when all retry attempts have been exhausted."""

    def __init__(self, attempts: int, last_exception: Exception):
        self.attempts = attempts
        self.last_exception = last_exception
        super().__init__(f"Failed after {attempts} attempts. Last error: {last_exception}")


def retry(
    max_attempts: int = 3,
    delay: float = 0.0,
    backoff_factor: float = 1.0,
    max_delay: float = 60.0,
    jitter: bool = False,
    exceptions: Union[Type[Exception], Tuple[Type[Exception], ...]] = Exception,
    on_retry: Optional[Callable[[int, Exception], None]] = None,
    reraise_as: Optional[Type[Exception]] = None
) -> Callable:
    """
    Decorator that retries a function call with configurable retry logic.

    Args:
        max_attempts: Maximum number of attempts (default: 3)
        delay: Initial delay between retries in seconds (default: 0.0)
        backoff_factor: Multiplier for delay after each attempt (default: 1.0)
        max_delay: Maximum delay between retries (default: 60.0)
        jitter: Add random jitter to delay to avoid thundering herd (default: False)
        exceptions: Exception type(s) to catch and retry on (default: Exception)
        on_retry: Callback function called on each retry attempt
        reraise_as: Exception type to reraise as instead of original exception

    Returns:
        Decorated function with retry logic

    Raises:
        ValueError: If max_attempts < 1 or delay/backoff_factor < 0
        RetryError: If reraise_as is not specified and all attempts fail
    """
    if max_attempts < 1:
        raise ValueError("max_attempts must be at least 1")
    if delay < 0:
        raise ValueError("delay must be non-negative")
    if backoff_factor < 0:
        raise ValueError("backoff_factor must be non-negative")
    if max_delay < 0:
        raise ValueError("max_delay must be non-negative")

    def decorator(func: Callable) -> Callable:
        @functools.wraps(func)
        def wrapper(*args, **kwargs) -> Any:
            last_exception = None
            current_delay = delay

            for attempt in range(1, max_attempts + 1):
                try:
                    return func(*args, **kwargs)
                except exceptions as e:
                    last_exception = e

                    if attempt == max_attempts:
                        # Final attempt failed
                        logger.error(
                            f"Function {func.__name__} failed after {max_attempts} attempts. "
                            f"Final error: {e}"
                        )
                        if reraise_as:
                            raise reraise_as(f"Failed after {max_attempts} attempts") from e
                        else:
                            raise RetryError(max_attempts, e) from e

                    # Log retry attempt
                    logger.warning(
                        f"Function {func.__name__} failed on attempt {attempt}/{max_attempts}. "
                        f"Error: {e}. Retrying in {current_delay:.2f}s..."
                    )

                    # Call retry callback if provided
                    if on_retry:
                        try:
                            on_retry(attempt, e)
                        except Exception as callback_error:
                            logger.error(f"Error in retry callback: {callback_error}")

                    # Sleep before next attempt
                    if current_delay > 0:
                        sleep_time = current_delay
                        if jitter:
                            # Add up to 25% jitter
                            jitter_amount = sleep_time * 0.25 * random.random()
                            sleep_time += jitter_amount

                        time.sleep(sleep_time)

                    # Calculate next delay with backoff
                    current_delay = min(current_delay * backoff_factor, max_delay)

            # This should never be reached, but just in case
            if reraise_as and last_exception:
                raise reraise_as(f"Failed after {max_attempts} attempts") from last_exception
            elif last_exception:
                raise RetryError(max_attempts, last_exception) from last_exception
            else:
                raise RetryError(max_attempts, Exception("Unknown error"))

        return wrapper
    return decorator


def retry_call(
    func: Callable,
    args: Tuple = (),
    kwargs: Optional[dict] = None,
    **retry_kwargs
) -> Any:
    """
    Retry a function call without using as a decorator.

    Args:
        func: Function to call
        args: Positional arguments for the function
        kwargs: Keyword arguments for the function
        **retry_kwargs: Arguments passed to retry decorator

    Returns:
        Result of the function call
    """
    if kwargs is None:
        kwargs = {}

    @retry(**retry_kwargs)
    def _wrapper():
        return func(*args, **kwargs)

    return _wrapper()


# Example usage and testing
if __name__ == "__main__":
    # Example 1: Basic retry with exponential backoff
    @retry(max_attempts=3, delay=1.0, backoff_factor=2.0)
    def flaky_api_call():
        import random
        if random.random() < 0.7:  # 70% chance of failure
            raise ConnectionError("API temporarily unavailable")
        return {"status": "success", "data": "important_data"}

    # Example 2: Retry specific exceptions only
    @retry(max_attempts=5, exceptions=(ConnectionError, TimeoutError))
    def network_operation():
        # This will only retry on ConnectionError or TimeoutError
        # Other exceptions will be raised immediately
        pass

    # Example 3: Using retry_call for one-off retries
    def unreliable_function(x, y):
        if random.random() < 0.5:
            raise ValueError("Random failure")
        return x + y

    try:
        result = retry_call(
            unreliable_function,
            args=(1, 2),
            max_attempts=3,
            delay=0.5
        )
        print(f"Result: {result}")
    except RetryError as e:
        print(f"All retries failed: {e}")
